// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;

import java.io.File;
import java.util.concurrent.atomic.AtomicReference;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.helpers.AbstractSimpleQueryModelVisitor;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.query.explanation.TelemetryMetricNames;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbCharacteristicSetEstimateTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI P1 = VF.createIRI("urn:star:p1");
	private static final IRI P2 = VF.createIRI("urn:star:p2");
	private static final IRI P3 = VF.createIRI("urn:star:p3");
	private static final int FULL_STAR_COUNT = 10;
	private static final int NOISE_PER_PREDICATE = 90;

	@Test
	void usesCharacteristicSetForCorrelatedSubjectStar(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadCorrelatedStarData(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
			LmdbPlannerAwait.awaitSketchesReady(store);

			try (SailRepositoryConnection connection = repository.getConnection()) {
				Explanation explanation = connection.prepareTupleQuery(String.join("\n",
						"SELECT ?s ?a ?b ?c WHERE {",
						"  ?s <urn:star:p1> ?a .",
						"  ?s <urn:star:p2> ?b .",
						"  ?s <urn:star:p3> ?c .",
						"}")).explain(Explanation.Level.Optimized);

				Join starJoin = findCharacteristicSetJoin((TupleExpr) explanation.tupleExpr());

				assertNotNull(starJoin, explanation::toString);
				assertEquals("lmdb-characteristic-set",
						starJoin.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE),
						explanation::toString);
				assertEquals(FULL_STAR_COUNT,
						starJoin.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS),
						FULL_STAR_COUNT * 0.25d, explanation::toString);
			}
		} finally {
			try {
				repository.shutDown();
			} finally {
				LmdbTestUtil.deleteDir(dataDir);
			}
		}
	}

	private static void loadCorrelatedStarData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			for (int i = 0; i < FULL_STAR_COUNT; i++) {
				Resource subject = VF.createIRI("urn:star:subject:" + i);
				connection.add(subject, P1, VF.createIRI("urn:star:a:" + i));
				connection.add(subject, P2, VF.createIRI("urn:star:b:" + i));
				connection.add(subject, P3, VF.createIRI("urn:star:c:" + i));
			}
			for (int i = 0; i < NOISE_PER_PREDICATE; i++) {
				connection.add(VF.createIRI("urn:star:p1-only:" + i), P1, VF.createIRI("urn:star:p1-value:" + i));
				connection.add(VF.createIRI("urn:star:p2-only:" + i), P2, VF.createIRI("urn:star:p2-value:" + i));
				connection.add(VF.createIRI("urn:star:p3-only:" + i), P3, VF.createIRI("urn:star:p3-value:" + i));
			}
		}
	}

	private static Join findCharacteristicSetJoin(TupleExpr tupleExpr) {
		AtomicReference<Join> result = new AtomicReference<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Join node) {
				String proof = node.getStringMetricPlanned("optimizer.rewriteProof");
				if (proof != null && proof.contains("CHARACTERISTIC_SET_STAR_ESTIMATE")) {
					result.compareAndSet(null, node);
				}
				super.meet(node);
			}
		});
		return result.get();
	}
}
